def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    result = ''
    value_to_numeral_dict = {
        1000: "M", 900: "CM", 500: "D", 400: "CD", 100: "C", 90: "XC", 50: "L", 40: "XL", 10: "X", 9: "IX", 5: "V", 4: "IV", 1: "I"
    }
    value_to_numeral_dict_reverse = {
        1000: "M", 900: "CM", 500: "D", 400: "CD", 100: "C", 90: "XC", 50: "L", 40: "XL", 10: "X", 9: "IX", 5: "V", 4: "IV", 1: "I"
    }
    value_to_numeral_dict_reverse_dict = {}
    value_to_numeral_dict_dict = {}
    for (value, numeral) in value_to_numeral_dict.items():
        value_to_numeral_dict_reverse_dict[numeral] = value
        value_to_numeral_dict_dict[value] = numeral

    dividend = number
    while dividend > 0:
        for (value, numeral) in value_to_numeral_dict_reverse_dict.items():
            quotient = int(dividend / value)
            dividend = dividend % value
            for _ in range(quotient):
                result += value_to_numeral_dict_dict[value]
    return result
